import React from 'react'

export const ProjectItem = (props) => {
  let {heading,img1,img2,img3,img4,img5,link1,link2}=props
  return (
    <div>
      <div>
        <img src={img1} alt="imgy" />
      </div>
      <div>
        <div>
          <img src={img2} alt="imgy" />
        </div>
        <div>
          <img src={img3} alt="imgy" />
        </div>
        <div>
          <img src={img4} alt="imgy" />
        </div>
        <div>
          <img src={img5} alt="imgy" />
        </div>
      </div>
      <div>
        <h1>{heading}</h1>
        <p><button><a href={link1}>Github</a></button> </p>
        <p><button><a href={link2}>Netlify</a></button></p>
      </div>
    </div>
  )
}
