import React from 'react'
import "../All_css/Skill.css"
import { SkillCard } from '../Component/SkillCard';
export const Skill = () => {
  const arr = [{ path: "/Images/html5.png", title: "Html" }, { path: "/Images/css.png", title:"Css"}, { path:"/Images/javascript.png", title:"Javascript"}, { path:"/Images/react.png", title:"React"}, { path:"/Images/github.png", title:"Github"}, { path:"/Images/bootstrap.png", title:"Bootstrap"}, { path:"/Images/mongodb.png", title:"Mongodb" }, { path: "/Images/typescript.png", title:"Typescript"}];
  return (
    <div id='skill' className='skill-outer'>
    <h1>Skill</h1>
    <div className="Skill" id='skill'>
      <div>
      {arr.map((el)=>{
        return <SkillCard {...el}/>
      })}
      </div>
    </div>
    </div>
  )
}
